def solve(arg1: dict) -> str:
    location = arg1.get('location')
    duration = arg1.get('duration')
    working_hours = arg1.get('working_hours')

    if location not in ['Bangalore', 'Chennai']:
        return 'Application rejected'

    if duration < 4 or duration > 16:
        return 'Application rejected'

    if working_hours != 8.5:
        return 'Application rejected'

    return 'Application accepted'
